import numpy as npfrom flask import Flask, requestfrom predict import make_predictionapp = Flask(__name__)@app.route("/", methods=["GET"])def index():    """Basic HTML response."""    body = (        "<html>"        "<body style='padding: 10px;'>"        "<h1>Welcome to my Flask API</h1>"        "</body>"        "</html>"    )    return body@app.route("/predict", methods=["POST"])def predict():    data_json = request.get_json()          bid = data_json["bid"]    ask = data_json["ask"]    delta = data_json["delta"]    gamma = data_json["gamma"]    theta = data_json["theta"]    vega = data_json["vega"]    implied_volatility = data_json["implied_volatility"]    data = np.array([[bid, ask, delta, gamma, theta, vega, implied_volatility]])    predictions = make_prediction(data)      return str(predictions)if __name__ == "__main__":    app.run()